class Solution {
public:
    string smallestNumber(string pattern) {
        int n = pattern.length();
        vector<int> num(n + 1, 0);

        for (int i = 0; i < n; i++) {
            if (pattern[i] == 'I') {
                for (int j = i + 1; j <= n; j++) {
                    num[j] = num[i] + 1;
                }
            } else {
                for (int j = i + 1; j <= n; j++) {
                    num[j] = num[i] - 1;
                }
            }
        }

        string result = "";
        for (int i = 1; i <= n; i++) {
            result += num[i];
        }

        return result;
    }
};
```

